//! Word-compliance spec tests for **Tables (§17.4)**.
//!
//! AUTO-GENERATED by the spec-word-compliance workflow. Each `#[test]` encodes a
//! declarative TestSpec: a behavioural rule drawn from ISO 29500-1 / ECMA-376 /
//! MS-OI29500, expressed as assertions over stemma's observable behaviour
//! (re-serialized `word/document.xml`, accept/reject text, validator report).
//!
//! IMPORTANT: A **FAIL here encodes a real Word-compliance gap** in stemma, not a
//! test bug. The expected values are the Word-faithful post-conditions: if an
//! assertion fails, stemma diverges from how Microsoft Word reads/writes the
//! markup. Do NOT weaken an assertion to make it pass — fix stemma at the source
//! (see CLAUDE.md "Fix at the source, not at the symptom"). Each assertion
//! message carries the rule text and the §refs so a failure is self-explanatory.

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::Document;

// ─── Prelude: minimal-.docx plumbing (mirrors the shared spec-suite prelude) ──

/// Build a valid minimal `.docx` whose `word/document.xml` body is `body_xml`
/// (wrapped in `<w:document><w:body>…</w:body></w:document>`).
///
/// `extra_parts` is a list of `(part_name, xml)` — e.g.
/// `("word/styles.xml", "<w:styles…/>")` — that are added to the zip AND given a
/// `[Content_Types].xml` override (the override `ContentType` is chosen from the
/// part's filename for the parts these specs need: styles.xml / numbering.xml).
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-types: defaults + the document.xml override, plus one override per
    // extra part. We map the few part kinds these specs use; anything else is a
    // programmer error in a spec, so fail fast rather than guessing a type.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part_name, _) in extra_parts {
        let content_type = match *part_name {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!(
                "make_docx: no content-type mapping for extra part {other:?} — add one before using it"
            ),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part_name}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // document.xml.rels: one relationship per extra part (styles / numbering),
    // keyed off the part kind so Word can resolve the reference.
    let mut doc_rel_entries = String::new();
    for (idx, (part_name, _)) in extra_parts.iter().enumerate() {
        let (rel_type, target) = match *part_name {
            "word/styles.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
                "styles.xml",
            ),
            "word/numbering.xml" => (
                "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
                "numbering.xml",
            ),
            other => panic!("make_docx: no relationship mapping for extra part {other:?}"),
        };
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rId{n}" Type="{rel_type}" Target="{target}"/>"#,
            n = 100 + idx
        ));
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, xml) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip for document.xml");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in docx");
    let mut out = String::new();
    file.read_to_string(&mut out)
        .expect("read word/document.xml");
    out
}

/// Parse `bytes`, re-serialize via the default export options, and return the
/// resulting `word/document.xml` (the passthrough output the `xml*` expectations
/// inspect).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse docx");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize docx");
    document_xml_of(&out)
}

/// Assert the document opens clean: stemma's validator reports `ok` with no
/// issues. The `ctx` is the rule + §refs so the failure is self-explanatory.
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = stemma::api::validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{ctx} — expected the document to open clean (validator ok, no issues), but got ok={} issues={:#?}",
        report.ok,
        report.issues
    );
}

/// Ordered-substring check: every part in `parts` must appear in `haystack`, each
/// after the previous one. This is the contains-translation of an `xmlRegex`
/// `A[\s\S]*B[\s\S]*C` pattern (the regex crate is not a dependency here).
fn ordered_contains(haystack: &str, parts: &[&str]) -> bool {
    let mut from = 0usize;
    for part in parts {
        match haystack[from..].find(part) {
            Some(rel) => from += rel + part.len(),
            None => return false,
        }
    }
    true
}

