#[test]
fn vmerge_absent_val_defaults_to_continue() {
    // ISO 29500-1 §17.18.57 (ST_Merge), §17.4.84 (vMerge): absent val == continue.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:type="auto" w:w="0"/></w:tblPr><w:tblGrid><w:gridCol w:w="4800"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:type="dxa" w:w="4800"/><w:vMerge w:val="restart"/></w:tcPr><w:p><w:r><w:t>Anchor</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:type="dxa" w:w="4800"/><w:vMerge/></w:tcPr><w:p/></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "vMerge absent val == continue (ISO 29500-1 §17.18.57, §17.4.84): a bare <w:vMerge/> below a restart in the same column is conformant; Word opens it without repair",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("vMerge"),
        "ISO 29500-1 §17.4.84 — vertical merge is a structural cell property; a passthrough re-serialization must retain the vMerge element so the continuation cell stays in the merged region; expected XML to contain vMerge, got:\n{xml}"
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Anchor",
        "ISO 29500-1 §17.4.84 — in a vertical merge the restart cell holds the content and continuation cells are empty; the accepted reading of the single merged region is exactly the anchor text 'Anchor' with no duplicate/empty-cell contribution"
    );
}

#[test]
fn tcpr_child_order_tcw_gridspan_vmerge_opens_clean() {
    // ISO 29500-1 §17.4.70 / ECMA-376 Annex A CT_TcPrInner: tcW, gridSpan, vMerge order.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:type="auto" w:w="0"/></w:tblPr><w:tblGrid><w:gridCol w:w="2400"/><w:gridCol w:w="2400"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:type="dxa" w:w="4800"/><w:gridSpan w:val="2"/><w:vMerge w:val="restart"/></w:tcPr><w:p><w:r><w:t>Span</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:type="dxa" w:w="4800"/><w:gridSpan w:val="2"/><w:vMerge/></w:tcPr><w:p/></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "tcPr child order tcW->gridSpan->vMerge (ISO 29500-1 §17.4.70 / Annex A CT_TcPrInner): this fixture lists them in schema order, so a Word-faithful validator must report zero ordering errors",
    );

    let xml = reserialize(&b);
    // xmlRegex tcW[\s\S]*gridSpan[\s\S]*vMerge — translated to an ordered-substring check.
    assert!(
        ordered_contains(&xml, &["tcW", "gridSpan", "vMerge"]),
        "ISO 29500-1 §17.4.70 / Annex A — re-serialized tcPr must preserve the schema sequence tcW -> gridSpan -> vMerge (NOTE: xmlRegex translated to ordered contains since regex is not a dep); a reorder/drop changes which markup Word reads; got:\n{xml}"
    );
}

#[test]
fn vmerge_bare_no_val_is_continue() {
    // ECMA-376 / ISO 29500-1 §17.4.84, §17.18.57 (ST_Merge): bare vMerge == continue.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="pct"/></w:tblPr><w:tblGrid><w:gridCol w:w="4680"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="4680" w:type="dxa"/><w:vMerge w:val="restart"/></w:tcPr><w:p><w:r><w:t>Anchor</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:w="4680" w:type="dxa"/><w:vMerge/></w:tcPr><w:p><w:r><w:t>Cont</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:val="restart""#),
        "ISO 29500-1 §17.4.84 — the first-row cell is the merge anchor and must serialize its vMerge restart marker; expected XML to contain w:val=\"restart\", got:\n{xml}"
    );
    // xmlRegex <w:vMerge\s*/> — a self-closing vMerge with no attributes. Translate
    // to: a self-closing vMerge open tag whose body (between "<w:vMerge" and "/>")
    // contains no attribute characters (only whitespace).
    let bare_vmerge = xml.match_indices("<w:vMerge").any(|(start, _)| {
        let rest = &xml[start + "<w:vMerge".len()..];
        // The element is a bare self-closing vMerge (no val attribute) iff the
        // text up to the closing '>' is just optional whitespace then '/'. Strip
        // a trailing '/' and require the remainder to be whitespace-only.
        match rest.find('>') {
            Some(gt) => {
                let inner = &rest[..gt];
                inner
                    .strip_suffix('/')
                    .map(|before_slash| before_slash.trim().is_empty())
                    .unwrap_or(false)
            }
            None => false,
        }
    });
    assert!(
        bare_vmerge,
        "ISO 29500-1 §17.4.84 — a continuation cell carries a valueless vMerge; Word omits val for continue, so the round-trip of a bare <w:vMerge/> must remain a bare (no-val) vMerge, confirming it was understood as continue rather than dropped or rewritten (NOTE: xmlRegex <w:vMerge\\s*/> translated to an attribute-absence check since regex is not a dep); got:\n{xml}"
    );

    assert_opens_clean(
        &b,
        "single-column column-aligned vMerge grid is conformant (ISO 29500-1 §17.4.84): Word opens it without repair",
    );
}

#[test]
fn tc_cnfstyle_direct_membership_roundtrips() {
    // ISO 29500-1 §17.4.7 (CT_TcPr), §17.3.1.8 (CT_Cnf), §17.7.6, Annex A.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:type="auto" w:w="0"/></w:tblPr><w:tblGrid><w:gridCol w:w="4680"/><w:gridCol w:w="4680"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:cnfStyle w:val="100000000000" w:firstRow="1"/></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:cnfStyle"),
        "ISO 29500-1 §17.4.7 — cnfStyle is a CT_TcPr child Word preserves on roundtrip; the re-serialized tcPr must still carry a cnfStyle element; expected XML to contain <w:cnfStyle, got:\n{xml}"
    );
    // xmlRegex <w:cnfStyle[^>]*w:firstRow="(1|true|on)" — translate: within the
    // cnfStyle open tag, w:firstRow is set to a truthy ST_OnOff value.
    let cnf_firstrow_on = match xml.find("<w:cnfStyle") {
        Some(start) => {
            let tag_end = xml[start..]
                .find('>')
                .map(|r| start + r)
                .unwrap_or(xml.len());
            let tag = &xml[start..tag_end];
            tag.contains(r#"w:firstRow="1""#)
                || tag.contains(r#"w:firstRow="true""#)
                || tag.contains(r#"w:firstRow="on""#)
        }
        None => false,
    };
    assert!(
        cnf_firstrow_on,
        "ISO 29500-1 §17.3.1.8 — CT_Cnf records the firstRow membership bit; the cell was authored firstRow=1 so the preserved cnfStyle must still assert firstRow (1/true/on) (NOTE: xmlRegex translated to a tag-scoped contains since regex is not a dep); got:\n{xml}"
    );

    assert_opens_clean(
        &b,
        "2x1 table with conformant tcPr/cnfStyle (ISO 29500-1 §17.4.7): must re-serialize to a document Word opens without repair",
    );
}

#[test]
fn tbl_header_explicit_off_is_not_header() {
    // ISO 29500-1 §17.4.49, §17.17.4 (ST_OnOff), Annex A CT_TrPr: val="0" == off.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:type="auto" w:w="0"/></w:tblPr><w:tblGrid><w:gridCol w:w="9360"/></w:tblGrid><w:tr><w:trPr><w:tblHeader w:val="0"/></w:trPr><w:tc><w:p><w:r><w:t>Row</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        !xml.contains("<w:tblHeader/>"),
        "ISO 29500-1 §17.4.49 + §17.17.4 — val=\"0\" means OFF, so the re-serialized row must not carry a bare (ON) <w:tblHeader/> element; got:\n{xml}"
    );
    assert!(
        !xml.contains("<w:tblHeader>"),
        "ISO 29500-1 §17.4.49 + §17.17.4 — an explicitly-off header must never be emitted as an enabled tblHeader; the row is not a repeated header per ST_OnOff; got:\n{xml}"
    );

    assert_opens_clean(
        &b,
        "minimal single-row table with explicit tblHeader off (ISO 29500-1 §17.4.49): must re-serialize to a document Word opens without repair",
    );
}

#[test]
fn trpr_cantsplit_tblheader_order_opens_clean() {
    // ISO 29500-1 §17.4.82, §17.4.6 (cantSplit), §17.4.49, Annex A CT_TrPrBase.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:type="auto" w:w="0"/></w:tblPr><w:tblGrid><w:gridCol w:w="4800"/></w:tblGrid><w:tr><w:trPr><w:cantSplit/><w:trHeight w:val="300" w:hRule="atLeast"/><w:tblHeader/></w:trPr><w:tc><w:tcPr><w:tcW w:type="dxa" w:w="4800"/></w:tcPr><w:p><w:r><w:t>Head</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:tc><w:tcPr><w:tcW w:type="dxa" w:w="4800"/></w:tcPr><w:p><w:r><w:t>Body</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "cantSplit+trHeight+tblHeader in CT_TrPrBase order (ISO 29500-1 §17.4.6, §17.4.49 / Annex A): a header row in schema order is fully conformant, so a Word-faithful validator reports no errors",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("cantSplit"),
        "ISO 29500-1 §17.4.6 — cantSplit ('keep row on one page') is a row property Word preserves; a passthrough re-serialization must not silently drop it, else the document loses pagination behaviour Word would have kept; expected XML to contain cantSplit, got:\n{xml}"
    );
}

#[test]
fn tcpr_hidemark_preserved_and_accepted() {
    // ISO 29500-1 §17.4.21 (hideMark), §17.4.70, Annex A CT_TcPrInner.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:type="auto" w:w="0"/><w:tblLayout w:type="autofit"/></w:tblPr><w:tblGrid><w:gridCol w:w="4800"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:type="dxa" w:w="4800"/><w:vAlign w:val="center"/><w:hideMark/></w:tcPr><w:p><w:r><w:t>Cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "hideMark after vAlign in CT_TcPr order (ISO 29500-1 §17.4.21 / Annex A): conformant markup Word opens without repair; the validator must report no errors",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("hideMark"),
        "ISO 29500-1 §17.4.21 — hideMark changes row-height measurement; Word preserves it across save, so a passthrough re-serialization must retain the element rather than silently discarding an unmodeled-but-valid cell property; expected XML to contain hideMark, got:\n{xml}"
    );
}
